// Pinned 2026-05-01 — single source of truth for all CodeMirror imports.
// Every consumer (uix-code wrapper + extension files like notes/editor/*) MUST
// import from this barrel. Direct imports from esm.sh produce duplicate
// @codemirror/state instances and break instanceof checks inside EditorState.create.
//
// Each module's `?deps=` lists the TRANSITIVE peer-dep closure (own peers +
// all of their peers, recursively). This guarantees that the URL of any
// module M, when imported directly via the barrel OR transitively via another
// module's internal cross-import, is byte-identical — so the browser dedupes
// to a single module instance and instanceof works.
//
// Two non-obvious rules behind the deps lists below:
//   1. Leaf modules (no peers — `state`, `@lezer/common`) MUST be imported
//      with NO `?deps=`. Adding deps gives them an X-ZE-tagged URL while
//      every other module references them at the canonical URL → mismatch.
//   2. Non-leaf modules need full transitive closure, not just direct peers.
//      e.g. `commands` direct peers are {language, state, view}, but language
//      itself has `@lezer/highlight` as a peer. If commands' deps omit
//      highlight, its internal language URL becomes X-ZE<state,view,common>
//      while the barrel's direct language URL is X-ZE<state,view,common,highlight>
//      — different URL, two language instances.

export * from "https://esm.sh/@codemirror/state@6.6.0";
export * from "https://esm.sh/@lezer/common@1.5.2";
export * from "https://esm.sh/@codemirror/view@6.41.1?deps=@codemirror/state@6.6.0";
export * from "https://esm.sh/@codemirror/language@6.12.3?deps=@codemirror/state@6.6.0,@codemirror/view@6.41.1,@lezer/common@1.5.2,@lezer/highlight@1.2.3";
export * from "https://esm.sh/@codemirror/commands@6.10.3?deps=@codemirror/language@6.12.3,@codemirror/state@6.6.0,@codemirror/view@6.41.1,@lezer/common@1.5.2,@lezer/highlight@1.2.3";
export * from "https://esm.sh/@codemirror/search@6.7.0?deps=@codemirror/state@6.6.0,@codemirror/view@6.41.1";
export * from "https://esm.sh/@codemirror/autocomplete@6.20.1?deps=@codemirror/language@6.12.3,@codemirror/state@6.6.0,@codemirror/view@6.41.1,@lezer/common@1.5.2,@lezer/highlight@1.2.3";
export * from "https://esm.sh/@codemirror/lang-css@6.3.1?deps=@codemirror/autocomplete@6.20.1,@codemirror/language@6.12.3,@codemirror/state@6.6.0,@codemirror/view@6.41.1,@lezer/common@1.5.2,@lezer/highlight@1.2.3";
export * from "https://esm.sh/@codemirror/lang-javascript@6.2.5?deps=@codemirror/autocomplete@6.20.1,@codemirror/language@6.12.3,@codemirror/state@6.6.0,@codemirror/view@6.41.1,@lezer/common@1.5.2,@lezer/highlight@1.2.3";
export * from "https://esm.sh/@codemirror/lang-html@6.4.11?deps=@codemirror/autocomplete@6.20.1,@codemirror/lang-css@6.3.1,@codemirror/lang-javascript@6.2.5,@codemirror/language@6.12.3,@codemirror/state@6.6.0,@codemirror/view@6.41.1,@lezer/common@1.5.2,@lezer/highlight@1.2.3";
export * from "https://esm.sh/@codemirror/lang-markdown@6.5.0?deps=@codemirror/autocomplete@6.20.1,@codemirror/lang-css@6.3.1,@codemirror/lang-html@6.4.11,@codemirror/lang-javascript@6.2.5,@codemirror/language@6.12.3,@codemirror/state@6.6.0,@codemirror/view@6.41.1,@lezer/common@1.5.2,@lezer/highlight@1.2.3,@lezer/markdown@1.6.3";
export * from "https://esm.sh/@lezer/markdown@1.6.3?deps=@lezer/common@1.5.2,@lezer/highlight@1.2.3";
export * from "https://esm.sh/@fsegurai/codemirror-theme-gruvbox-dark@6.2.5?deps=@codemirror/language@6.12.3,@codemirror/state@6.6.0,@codemirror/view@6.41.1,@lezer/common@1.5.2,@lezer/highlight@1.2.3";
